import HTTPClient from "./HTTPClient";
import {RegistrationRecord} from './index';

/**
 * Registry Client
 * @class RegistryClient
 * @extends HTTPClient
 * @param {String} host Registry host
 * @param {String} port Registry port
 */
class RegistryClient extends HTTPClient {

    private static _instance:RegistryClient;

    public static createInstance(host:string, port:number):RegistryClient {
        return new RegistryClient(host, port);
    }

    public static get instance():RegistryClient {
        return RegistryClient._instance;
    }

    constructor(public host:string, public port:number) {
        super(host, port);
        if(RegistryClient._instance) {
            throw new Error('Registry Client is a singleton');
        }
        RegistryClient._instance = this;
    }

    /**
     * Add new record.
     * @method RegistryClient#addNewRecord
     * @param {RegistrationRecord} record
     * @param {Function} callback
     */
    addNewRecord(record:RegistrationRecord, callback:(error:Error) => void):void {
        this.sendRequest('PUT', '/registry', JSON.stringify(record), callback);
    }

    /**
     * Edit record.
     * @method RegistryClient#editRecord
     * @param {RegistrationRecord} record
     * @param {Function} callback
     */
    editRecord(record:RegistrationRecord, callback:(error:Error) => void):void {
        this.sendRequest('POST', '/registry', JSON.stringify(record), callback);
    }

    /**
     * Delete record.
     * @method RegistryClient#deleteRecord
     * @param {RegistrationRecord} record
     * @param {Function} callback
     */
    deleteRecord(record:RegistrationRecord, callback:(error:Error) => void):void {
        this.sendRequest('DELETE', '/registry', JSON.stringify(record), callback);
    }

    /**
     * Get record.
     * @method RegistryClient#getRecords
     * @param {Function} callback
     */
    getRecords(callback:(error:Error, records?:Array<RegistrationRecord>) => void):void {
        this.get('/registry', (error:Error, records:{records:Array<RegistrationRecord>}) => {
            callback(error, records.records);
        });
    }
}

export default RegistryClient;